const usuariosFollowUp = [];
const agora = new Date();

// Tabela de follow-ups e tempos exatos em minutos
const followUps = [
  { numero: 1, minutos: 10, mensagem: "🏡 Tudo bem? Só passando para confirmar se conseguiu ver nossa mensagem anterior 😊" },
  { numero: 2, minutos: 30, mensagem: "📞 Oi novamente! Vi que ainda não tivemos retorno. Posso te ajudar a encontrar o imóvel ideal hoje?" },
  { numero: 3, minutos: 60, mensagem: "💬 Tudo certo por aí? Notei que faz um tempinho desde nosso último contato. Quer que eu te envie algumas opções de imóveis que combinam com seu perfil?" },
  { numero: 4, minutos: 1440, mensagem: "☀️ Bom dia! Passou 1 dia desde nosso último contato. Caso ainda esteja em busca de um imóvel, posso te mostrar as melhores oportunidades que temos hoje!" },
  { numero: 5, minutos: 2880, mensagem: "🏠 Olá! Aqui é da *Luz Imobiliária*. Ainda está buscando um imóvel? Temos novas opções que acabaram de chegar — posso te enviar algumas?" },
  { numero: 6, minutos: 4320, mensagem: "✨ Oi! Faz três dias desde nossa última conversa. Só reforçando: estamos à disposição para te ajudar a encontrar o imóvel perfeito, no seu tempo." },
  { numero: 7, minutos: 5760, mensagem: "🙏 Tudo bem? Aqui é da *Luz Imobiliária*. Essa é nossa última mensagem por enquanto — mas quando quiser retomar a conversa sobre imóveis, estaremos por aqui!" }
];

for (const item of $input.all()) {
  const dado = item.json;
  const telefone = dado.telefone;
  const resposta = dado.resposta;

  // Corrige fuso horário para -03:00, se não houver
  const horarioStr = (dado.horario.includes("Z") || dado.horario.includes("+"))
    ? dado.horario
    : dado.horario + "-03:00";
  const horario = new Date(horarioStr);

  const diferencaMinutos = Math.floor((agora - horario) / (1000 * 60));

  // Só processa respostas da IA
  if (resposta !== "IA") continue;

  // Verifica se há algum follow-up exatamente igual ao tempo decorrido
  const followAtual = followUps.find(f => f.minutos === diferencaMinutos);

  if (followAtual) {
    usuariosFollowUp.push({
      json: {
        telefone,
        minutosPassados: diferencaMinutos,
        followUp: followAtual.numero,
        mensagem: followAtual.mensagem
      }
    });
  }
}

return usuariosFollowUp;

// --- 1. LER DADOS DO WEBHOOK (O Classificador) ---
let originalMsgType = 'text'; // Padrão
let numero_cliente = null;
let nome_instancia = null; 
let nome_cliente_pushname = null;

try {
  // 🔴 Use o nome exato do seu nó 'normalizacao' 🔴
  const dadosMensagem = $('normalizacao').first().json; 
  originalMsgType = dadosMensagem.msg.type_msg;
  numero_cliente = dadosMensagem.msg.numero;
  nome_instancia = dadosMensagem.instancia; 

  if (numero_cliente && numero_cliente.includes('@')) {
    numero_cliente = numero_cliente.split('@')[0];
  }
} catch (error) {
  throw new Error("Não foi possível ler os dados do nó 'normalizacao'. Verifique o nome. Erro: " + error.message);
}

try {
  // 🔴 Use o nome exato do seu nó 'Agente SDR' 🔴
  const dadosSDR = $('Agente SDR').first().json;
  nome_cliente_pushname = dadosSDR.body.data.pushName;
} catch (e) {
  console.warn("Não foi possível ler o 'pushName' do nó 'Agente SDR'.");
  nome_cliente_pushname = ""; 
}
// --- FIM DA LEITURA ---


// --- 2. PROCESSAR OS ITENS DA IA ---
const itemsIn = items; // A resposta da IA (OS 6 ITENS)
const itemsOut = []; // O array de saída (agora vai ter 8+ itens)

// Regex para imagens
const imageRegex = /^https?:\/\/.+\.(jpg|jpeg|png|gif|webp)(\?.*)?$/i;

// Loop principal (processando os 6 itens)
for (const item of itemsIn) {

  const outputText = item.json.output;

  // Limpa o lixo (---, text, `)
  const cleanedText = outputText
    .replace(/^---\\n/, '') 
    .replace(/^---/, '')    
    .replace(/^text/, '') 
    .replace(/`/g, '')    
    .trim();             

  let messageType = 'text'; // Padrão

  // --- 3. LÓGICA DE CLASSIFICAÇÃO E SPLIT ---

  // Prioridade 1: O usuário mandou áudio?
  if (originalMsgType === 'AudioMessage') { 
    messageType = 'AudioMessage';

    // Adiciona o item de áudio (ignora os vazios)
    if (cleanedText) {
      // <-- CORREÇÃO 1: Limpa as aspas do conteúdo de áudio/texto
      const finalContent = cleanedText.replace(/^"|"$/g, '');

      itemsOut.push({
        json: {
          messageType: messageType, 
          content: finalContent, // <-- Usa o conteúdo limpo
          numero_cliente: numero_cliente, 
          nome_instancia: nome_instancia,
          nome_cliente: nome_cliente_pushname
        }
      });
    }
  } 
  // Prioridade 2: A IA mandou uma imagem?
  else if (imageRegex.test(cleanedText)) {
    // SIM, É UMA IMAGEM.
    // Mas a IA pode ter juntado texto nela (como nos itens 2, 3, 4 do seu log).

    const separator = '---';
    const separatorIndex = cleanedText.indexOf(separator);

    if (separatorIndex !== -1) {
      // ENCONTROU O SEPARADOR! A IA JUNTOU IMAGEM E TEXTO.

      // Pega só a imagem (antes do '---')
      const imageUrl = cleanedText.substring(0, separatorIndex).trim();
      // Pega só o texto (depois do '---')
      let textContent = cleanedText.substring(separatorIndex + separator.length).trim();

      // Adiciona a IMAGEM como um item
      itemsOut.push({
        json: {
          messageType: 'image', 
          content: imageUrl,
          numero_cliente: numero_cliente, 
          nome_instancia: nome_instancia,
          nome_cliente: nome_cliente_pushname
        }
      });

      // Adiciona o TEXTO como um item SEPARADO
      if (textContent) { 
        // <-- CORREÇÃO 2: Limpa as aspas APENAS do texto que acompanha a imagem
        textContent = textContent.replace(/^"|"$/g, '');

        itemsOut.push({
          json: {
            messageType: 'text', 
            content: textContent, // <-- Usa o conteúdo limpo
            numero_cliente: numero_cliente, 
            nome_instancia: nome_instancia,
            nome_cliente: nome_cliente_pushname
          }
        });
      }
    } else {
      // Não achou '---', é só uma imagem (raro)
       itemsOut.push({
        json: {
          messageType: 'image', 
          content: cleanedText, // (Não precisa limpar aspas de URLs)
          numero_cliente: numero_cliente, 
          nome_instancia: nome_instancia,
          nome_cliente: nome_cliente_pushname
        }
      });
    }
  }
  // Prioridade 3: Se não, é texto.
  else {
    messageType = 'text';

    // Adiciona o item de texto (ignora os vazios, como o item 5)
    if (cleanedText) { 
      // <-- CORREÇÃO 3: Limpa as aspas do conteúdo de texto normal
      const finalContent = cleanedText.replace(/^"|"$/g, '');

      itemsOut.push({
        json: {
          messageType: messageType, 
          content: finalContent, // <-- Usa o conteúdo limpo
          numero_cliente: numero_cliente, 
          nome_instancia: nome_instancia,
          nome_cliente: nome_cliente_pushname
        }
      });
    }
  }
}

// 4. Retorna os itens "carimbados" e "fatiados" para o Loop
return itemsOut;

